+			bodyLines := strings.Split(msg.Description, "\n")
+			for _, line := range bodyLines {
+				fmt.Printf("%s  %s\n", indent, line)
+			}
+		}
+		fmt.Println()
+	}
+
+	fmt.Printf("Total: %d messages in thread\n\n", len(threadMessages))
